const rows = $input.all().map(i => i.json);
const latest = {};
const previous = {};
for (const row of rows) {
  const rn = typeof row.rn === 'string' ? parseInt(row.rn, 10) : row.rn;
  if (rn === 1) latest[row.metrica] = row;
  else if (rn === 2) previous[row.metrica] = row;
}

const breach = (valor, threshold, op) => {
  if (valor === null || valor === undefined || valor === '') return false;
  const v = parseFloat(valor);
  if (Number.isNaN(v)) return false;
  return op === '>' ? v > threshold : v < threshold;
};

const alerts = [];

// LIVENESS — horas_desde_ultima (NULL-safe + guarda NULL-com-histórico)
const livKey = 'movimentacoes_horas_desde_ultima';
const liv = latest[livKey];
if (liv) {
  const v = liv.valor;
  const totalRows = (liv.detalhes && liv.detalhes.total_rows) || 0;
  if ((v === null || v === undefined || v === '') && totalRows > 0) {
    alerts.push({ nivel: 'CRITICAL', metrica: livKey, valor: 'NULL', threshold: 'NULL-com-historico', created_at: liv.created_at, contexto: 'Banco tem ' + totalRows + ' movs mas métrica é NULL.', acao: 'Investigar coalescing da stored function.' });
  } else if (breach(v, 96, '>')) {
    alerts.push({ nivel: 'CRITICAL', metrica: livKey, valor: parseFloat(v).toFixed(2) + 'h', threshold: '> 96h', created_at: liv.created_at, contexto: 'Mais de 4 dias sem movimentação (' + totalRows + ' rows históricas).', acao: 'Verificar UazAPI + workflow Principal.' });
  } else if (breach(v, 48, '>')) {
    alerts.push({ nivel: 'WARN', metrica: livKey, valor: parseFloat(v).toFixed(2) + 'h', threshold: '> 48h', created_at: liv.created_at, contexto: 'Mais de 2 dias sem movimentação (' + totalRows + ' rows históricas).', acao: 'Verificar se é pausa esperada (fim de semana/feriado).' });
  }
}

// QUALIDADE — pct_outros com guarda de amostra mínima
const pctKey = 'movimentacoes_24h_pct_outros';
const pct = latest[pctKey];
if (pct) {
  const v = pct.valor;
  const total24h = (pct.detalhes && pct.detalhes.total) || 0;
  if (total24h >= 5 && breach(v, 80, '>')) {
    alerts.push({ nivel: 'CRITICAL', metrica: pctKey, valor: parseFloat(v).toFixed(1) + '%', threshold: '> 80% com total >= 5', created_at: pct.created_at, contexto: 'Classificador em ' + total24h + ' movs colocou maioria em "Outros".', acao: 'Revisar agente de categorização.' });
  } else if (total24h >= 3 && breach(v, 50, '>')) {
    alerts.push({ nivel: 'WARN', metrica: pctKey, valor: parseFloat(v).toFixed(1) + '%', threshold: '> 50% com total >= 3', created_at: pct.created_at, contexto: total24h + ' movs últimas 24h, alta proporção em "Outros".', acao: 'Monitorar próximas horas.' });
  }
}

// INTEGRIDADE — categorias_total invariante
const catKey = 'categorias_total';
const cat = latest[catKey];
if (cat) {
  const v = parseFloat(cat.valor);
  if (!Number.isNaN(v) && v !== 62) {
    alerts.push({ nivel: 'CRITICAL', metrica: catKey, valor: String(v), threshold: 'invariante = 62', created_at: cat.created_at, contexto: 'Catálogo de categorias mudou (' + v + ' !== 62).', acao: 'Auditar DELETE/INSERT em categorias.' });
  }
}

// MONOTONICIDADE — mapeamento_total nunca decresce
const mapKey = 'mapeamento_total';
const mapCur = latest[mapKey];
const mapPrev = previous[mapKey];
if (mapCur && mapPrev) {
  const vCur = parseFloat(mapCur.valor);
  const vPrev = parseFloat(mapPrev.valor);
  if (!Number.isNaN(vCur) && !Number.isNaN(vPrev) && vPrev > vCur) {
    alerts.push({ nivel: 'CRITICAL', metrica: mapKey, valor: vCur + ' (era ' + vPrev + ')', threshold: 'monotônico crescente', created_at: mapCur.created_at, contexto: 'Aprendizado decresceu entre batches consecutivos.', acao: 'Investigar DELETE em mapeamento_categorias.' });
  }
}

// META — cron vivo (latência desde último batch)
const anyKey = Object.keys(latest)[0];
if (anyKey) {
  const any = latest[anyKey];
  const minutos = (Date.now() - new Date(any.created_at).getTime()) / 60000;
  if (minutos > 180) {
    alerts.push({ nivel: 'FATAL', metrica: 'cron_liveness', valor: minutos.toFixed(0) + 'min', threshold: '> 180min', created_at: any.created_at, contexto: 'MetricasCron não escreve há mais de 3h.', acao: 'Verificar schedule trigger. Intervenção manual.' });
  } else if (minutos > 75) {
    alerts.push({ nivel: 'CRITICAL', metrica: 'cron_liveness', valor: minutos.toFixed(0) + 'min', threshold: '> 75min', created_at: any.created_at, contexto: 'MetricasCron há ' + minutos.toFixed(0) + ' min sem novo batch.', acao: 'Cron deveria rodar 1x/h. Investigar scheduler.' });
  }
}

return alerts.map(a => ({ json: a }));

const emojiMap = { INFO: '📈', WARN: '⚠️', CRITICAL: '🚨', FATAL: '🛑' };
const alerts = $input.all().map(i => i.json);

return alerts.map(alert => {
  const batchBrt = new Date(alert.created_at).toLocaleString('pt-BR', {
    timeZone: 'America/Sao_Paulo',
    day: '2-digit', month: '2-digit', year: 'numeric',
    hour: '2-digit', minute: '2-digit'
  });
  return {
    json: {
      emoji: emojiMap[alert.nivel] || '❓',
      nivel: alert.nivel,
      metrica: alert.metrica,
      valor: alert.valor,
      threshold: alert.threshold,
      batch_brt: batchBrt,
      contexto: alert.contexto || '—',
      acao: alert.acao || 'Verificar playbook correspondente.'
    }
  };
});

